const data = $input.first().json;

// Extract data

const candidate = {

    name: data.candidate_name,

    job_title: data.job_title,

    experience: data.experience_level

};

const job = {

    required_skills: data.required_skills,

    optional_skills: data.optional_skills,

    difficulty: data.difficulty

};

const transcript = data.full_transcript;

const questions = data.questions;

// Build questions and answers section

let qaSection = '';

questions.forEach((q, index) => {

    const questionKey = `question_${q.question_id}`;

    const answer = transcript[questionKey]?.answer || 'NOT ANSWERED';

    const wordCount = transcript[questionKey]?.wordCount || 0;

    // Handle evaluation_criteria - it's stored as JSONB object { criteria: [...] }

    let criteriaList = [];

    if (q.evaluation_criteria) {

        if (Array.isArray(q.evaluation_criteria)) {

            criteriaList = q.evaluation_criteria;

        } else if (q.evaluation_criteria.criteria && Array.isArray(q.evaluation_criteria.criteria)) {

            criteriaList = q.evaluation_criteria.criteria;

        } else if (typeof q.evaluation_criteria === 'object') {

            // Try to extract array from object values

            criteriaList = Object.values(q.evaluation_criteria).flat().filter(c => c);

        }

    }

    // Handle key_points - same structure as evaluation_criteria

    let keyPointsList = [];

    if (q.key_points) {

        if (Array.isArray(q.key_points)) {

            keyPointsList = q.key_points;

        } else if (q.key_points.points && Array.isArray(q.key_points.points)) {

            keyPointsList = q.key_points.points;

        } else if (typeof q.key_points === 'object') {

            keyPointsList = Object.values(q.key_points).flat().filter(p => p);

        }

    }

    qaSection += `

=== QUESTION ${q.question_id} ===

Category: ${q.category}

Difficulty: ${q.difficulty}

Time Limit: ${q.time_limit} seconds

Question: ${q.question_text}

Evaluation Criteria:

${criteriaList.length > 0 ? criteriaList.map(c => `- ${c}`).join('\n') : '- Technical accuracy\n- Clarity of explanation\n- Depth of knowledge'}

Key Points Expected:

${keyPointsList.length > 0 ? keyPointsList.map(p => `- ${p}`).join('\n') : '- Not specified'}

Candidate's Answer (${wordCount} words):

"${answer}"

---

`;

});

// Build AI prompt

const prompt = `You are an expert technical interviewer evaluating a candidate.

CANDIDATE PROFILE:

- Name: ${candidate.name}

- Position Applied: ${candidate.job_title}

- Experience Level: ${candidate.experience}

JOB REQUIREMENTS:

- Required Skills: ${job.required_skills}

- Optional Skills: ${job.optional_skills}

- Difficulty Level: ${job.difficulty}

INTERVIEW QUESTIONS & ANSWERS:

${qaSection}

EVALUATION TASK:

Analyze each answer and provide scores. Consider:

1. Technical accuracy and depth

2. Clarity of communication

3. Relevance to the question

4. Demonstrated experience level

For answers that are incomplete or very short (< 5 words), give low scores (0-3).

Return your evaluation in this EXACT JSON format (ONLY JSON, no markdown):

{

  "question_scores": [

    {

      "question_id": 1,

      "score": 8,

      "feedback": "Detailed feedback here"

    }

  ],

  "strengths": ["strength 1", "strength 2"],

  "weaknesses": ["weakness 1", "weakness 2"],

  "overall_feedback": "Overall assessment paragraph",

  "interview_score": 75

}

The interview_score should be the average of all question scores (0-100 scale).`;

return [{

    json: {

        prompt: prompt,

        candidate_name: candidate.name,

        candidate_email: data.candidate_email,

        video_assessment_id: data.video_assessment_id,

        // Old client-side report

        client_security_report: data.client_security_report,

        // NEW: Pass Python analysis data forward

        violations_summary: data.violations_summary,

        attention_metrics: data.attention_metrics,

        face_detection: data.face_detection,

        emotion_analysis: data.emotion_analysis,

        questions: questions,

        transcript: transcript

    }

}];

const aiOutput = $input.first().json.output;
const data = $('Build Evaluation Prompt').first().json;

// Get BOTH security reports
const clientSecurityReport = data.client_security_report || {}; // From JavaScript
const pythonAnalysis = {
    violations_summary: data.violations_summary || {},
    attention_metrics: data.attention_metrics || {},
    face_detection: data.face_detection || {},
    emotion_analysis: data.emotion_analysis || {}
};

console.log('📊 Security Analysis Sources:');
console.log('Client-side violations:', clientSecurityReport.violations?.length || 0);
console.log('Python violations:', pythonAnalysis.violations_summary.total_violations || 0);

// ============================================
// UPDATED SECURITY SCORING (STRICT RULE BASED)
// ============================================

let securityScore = 100;
let deductions = [];

// RULE-BASED CHEATING CONDITIONS
const metrics = clientSecurityReport.metrics || {};
const multipleFaces = pythonAnalysis.face_detection?.multiple_faces_flag_count || 0;

const cheatingDetected =
    (metrics.tabSwitches > 0) ||
    (metrics.keystrokeCount > 3) ||
    (metrics.multipleMonitors === true) ||
    (metrics.keystrokeExceeded === true) ||
    (multipleFaces > 1);

if (cheatingDetected) {
    securityScore = 0;
    deductions.push("CHEATING DETECTED: Security score set to 0 due to suspicious activity.");
} else {

    // ============================================
    // ORIGINAL SECURITY SCORING LOGIC (UNCHANGED)
    // ============================================

    // 1. FACE DETECTION (from Python)
    if (multipleFaces > 0) {
        const penalty = multipleFaces * 10;
        securityScore -= penalty;
        deductions.push(`Multiple faces detected: -${penalty} (${multipleFaces} times)`);
    }

    // 2. ATTENTION METRICS (from Python)
    const attentionRate = pythonAnalysis.attention_metrics?.attention_rate_percent || 100;
    const lookAwayCount = pythonAnalysis.attention_metrics?.look_away_count || 0;

    if (attentionRate < 70) {
        securityScore -= 20;
        deductions.push(`Low attention rate (${attentionRate.toFixed(1)}%): -20`);
    } else if (attentionRate < 85) {
        securityScore -= 10;
        deductions.push(`Moderate attention rate (${attentionRate.toFixed(1)}%): -10`);
    }

    if (lookAwayCount > 15) {
        securityScore -= 5;
        deductions.push(`Excessive looking away (${lookAwayCount} times): -5`);
    }

    // 3. EMOTION ANALYSIS (from Python)
    const emotions = pythonAnalysis.emotion_analysis?.emotion_distribution_percent || {};
    const dominantEmotion = pythonAnalysis.emotion_analysis?.dominant_emotion || 'unknown';

    if (emotions.fearful > 25 || emotions.angry > 20) {
        securityScore -= 10;
        deductions.push(`Suspicious emotional pattern: -10`);
    }

    // 4. CLIENT-SERVER mismatch detection
    const clientViolations = clientSecurityReport.violations?.length || 0;
    const pythonViolations = pythonAnalysis.violations_summary?.total_violations || 0;

    if (clientViolations === 0 && pythonViolations > 5) {
        securityScore -= 15;
        deductions.push(`Possible tampering detected (client vs server mismatch): -15`);
    }

    // 5. TAB SWITCHING
    const tabSwitches = metrics.tabSwitches || 0;
    if (tabSwitches > 0) {
        const penalty = tabSwitches * 5;
        securityScore -= penalty;
        deductions.push(`Tab switches: -${penalty} (${tabSwitches} times)`);
    }

    // Ensure bounds
    securityScore = Math.max(0, Math.min(100, securityScore));
}

// Determine severity
let severity = 'low';
if (securityScore < 50) severity = 'high';
else if (securityScore < 75) severity = 'medium';

// ============================================
// CALCULATE FINAL SCORE
// ============================================

const interviewScore = aiOutput.interview_score || 0;

// WHEN CHEATING → ignore security weight
const finalScore = securityScore === 0
    ? Math.round(interviewScore)
    : Math.round((interviewScore * 0.7) + (securityScore * 0.3));

// Determine recommendation
let recommendation = 'reject';
if (securityScore === 0) recommendation = 'reject';
else if (finalScore >= 70 && securityScore >= 60) recommendation = 'hire';
else if (finalScore >= 50) recommendation = 'maybe';

console.log('📈 Final Scores:');
console.log(`Interview: ${interviewScore}/100`);
console.log(`Security: ${securityScore}/100`);
console.log(`Final: ${finalScore}/100`);
console.log(`Recommendation: ${recommendation}`);

// ============================================
// RETURN ENHANCED DATA
// ============================================

return [{
    json: {
        video_assessment_id: data.video_assessment_id,

        interview_score: interviewScore,
        security_score: securityScore,
        final_score: finalScore,

        question_scores: aiOutput.question_scores,

        security_violations_count: pythonAnalysis.violations_summary?.total_violations || 0,
        security_severity: severity,

        security_details: {
            python_analysis: pythonAnalysis,
            client_report: clientSecurityReport,
            deductions: deductions,
            cheatingDetected,
            multiple_faces_count: multipleFaces,
            metrics
        },

        strengths: aiOutput.strengths,
        weaknesses: aiOutput.weaknesses,
        overall_feedback: aiOutput.overall_feedback,
        recommendation: recommendation
    }
}];

const data = $input.first().json;

return [{
  json: {
    video_assessment_id: data.video_assessment_id,
    interview_score: data.interview_score,
    security_score: data.security_score,
    final_score: data.final_score,

    // Convert to JSON strings for JSONB columns
    question_scores: JSON.stringify(data.question_scores),
    security_details: JSON.stringify(data.security_details),

    strengths: data.strengths,
    weaknesses: data.weaknesses,

    overall_feedback: data.overall_feedback,
    recommendation: data.recommendation,
    security_violations_count: data.security_violations_count,
    security_severity: data.security_severity,

    // NEW FIELDS FOR HUMAN OVERRIDE
    final_decision: null,
    decision_by: null,
    decision_at: null
  }
}];

const data = $('Store Evaluation Results').first().json;   // real evaluation details
const candidateData = $('Build Evaluation Prompt').first().json;

// Format question scores as HTML list
const questionsList = data.question_scores.map(q =>
  `<li><strong>Question ${q.question_id}:</strong> ${q.score}/10 - ${q.feedback}</li>`
).join('');

// Format arrays
const strengthsList = data.strengths.length > 0
  ? data.strengths.map(s => `<li>${s}</li>`).join('')
  : '<li><em>None identified</em></li>';

const weaknessesList = data.weaknesses.map(w => `<li>${w}</li>`).join('');

// RETURN RESULT
return [
  {
    json: {
      html: `
        <h2>Candidate Evaluation Report</h2>
        <p><strong>Candidate:</strong> ${candidateData.candidate_name}</p>
        <p><strong>Final Score:</strong> ${data.final_score}/100</p>

        <h3>Question Scores</h3>
        <ul>${questionsList}</ul>

        <h3>Strengths</h3>
        <ul>${strengthsList}</ul>

        <h3>Weaknesses</h3>
        <ul>${weaknessesList}</ul>
      `
    }
  }
];

return [{
    json: {
        success: true,
        message: 'Evaluation completed and email sent',
        video_assessment_id: $('Store Evaluation Results').first().json.video_assessment_id,
        final_score: $('Store Evaluation Results').first().json.final_score,
        recommendation: $('Store Evaluation Results').first().json.recommendation
    }
}];

return [{
  json: {
    ...$('Store Evaluation Results').first().json,
    ...$json,  // includes response from approval
  }
}];
